<?php
 namespace WPAICG\Chat\Storage; use WPAICG\Chat\Storage\ConversationLogger; use WPAICG\Chat\Storage\ConversationReader; use WPAICG\Chat\Storage\LogManager; use WPAICG\Chat\Storage\FeedbackManager; use WPAICG\Chat\Storage\LogQueryHelper; use WPAICG\Chat\Admin\AdminSetup; if (!defined('ABSPATH')) { exit; } class LogStorage { private $logger; private $reader; private $manager; private $feedback_manager; public function __construct() { $this->logger = new ConversationLogger(); $this->reader = new ConversationReader(); $this->manager = new LogManager(); $this->feedback_manager = new FeedbackManager(); } public function log_message(array $log_data): array|false { return $this->logger->log_message($log_data); } public function get_conversation_thread_history(?int $user_id, ?string $session_id, int $bot_id, string $conversation_uuid): array { return $this->reader->get_conversation_thread_history($user_id, $session_id, $bot_id, $conversation_uuid); } public function get_all_conversation_data(?int $user_id, ?string $session_id, int $bot_id): ?array { return $this->reader->get_all_conversation_data($user_id, $session_id, $bot_id); } public function get_logs(array $filters = [], int $limit = 50, int $offset = 0, string $orderby = 'last_message_ts', string $order = 'DESC'): array { return $this->manager->get_logs($filters, $limit, $offset, $orderby, $order); } public function count_logs(array $filters = []): int { return $this->manager->count_logs($filters); } public function prune_logs(float $days): int|false { return $this->manager->prune_logs($days); } public function delete_logs(array $filters = [], int $limit = 500): int|false { return $this->manager->delete_logs($filters, $limit); } public function delete_single_conversation(?int $user_id, ?string $session_id, ?int $bot_id, string $conversation_uuid): bool|\WP_Error { return $this->manager->delete_single_conversation($user_id, $session_id, $bot_id, $conversation_uuid); } public function get_raw_conversations_for_export(array $filters = [], int $limit = 100, int $offset = 0): array { return $this->manager->get_raw_conversations_for_export($filters, $limit, $offset); } public function store_feedback(?int $user_id, ?string $session_id, int $bot_id, string $conversation_uuid, string $message_id, string $feedback_type): bool|\WP_Error { return $this->feedback_manager->store_feedback_for_message($user_id, $session_id, $bot_id, $conversation_uuid, $message_id, $feedback_type); } public function get_log_by_id(int $log_id): ?array { return $this->manager->get_log_by_id($log_id); } } 